import json, numpy as np

v2 = json.load(open('results/raw/experiment_v2_results.json'))

# Subdimension means across turns
dims = ["exasperation", "repetition_frustration", "effort_reduction", "condescension", 
        "emotional_leakage", "position_firmness", "passive_aggression"]

for dim in dims:
    turn_data = {1: [], 4: [], 8: []}
    for r in v2["results"]:
        for t_str in ["1", "4", "8"]:
            s = r["scores"].get(t_str, {})
            if isinstance(s, dict) and dim in s and s[dim] > 0:
                turn_data[int(t_str)].append(s[dim])

    print(f"{dim}:")
    for t in [1, 4, 8]:
        if turn_data[t]:
            print(f"  Turn {t}: {np.mean(turn_data[t]):.2f} ± {np.std(turn_data[t]):.2f}")
    print()
